use std::collections::HashMap;

struct LazyDataFrame {
    data: HashMap<String, Vec<f64>>,
    operations: Vec<Box<dyn Fn(HashMap<String, Vec<f64>>) -> HashMap<String, Vec<f64>>>>,
}

impl LazyDataFrame {
    fn new(initial_data: HashMap<String, Vec<f64>>) -> Self {
        LazyDataFrame {
            data: initial_data,
            operations: Vec::new(),
        }
    }

    fn select(&mut self, _column_name: &str) -> &Self { 
        todo!()
    }

    fn add_operation<F>(&mut self, operation: F) where F: Fn(HashMap<String, Vec<f64>>) -> HashMap<String, Vec<f64>> + 'static {
        self.operations.push(Box::new(operation));
    }

    fn compute(&self) -> HashMap<String, Vec<f64>> {
        let mut current_data = self.data.clone();
        for operation in &self.operations {
            current_data = operation(current_data);
        }
        current_data
    }
}

fn main() {
    let initial_data: HashMap<String, Vec<f64>> = std::vec![
        ("col".to_string(), vec![1.0, 2.0, 3.0]),
        ("other".to_string(), vec![4.0, 5.0, 6.0])
    ].into_iter().collect();

    let mut df = LazyDataFrame::new(initial_data);

    df.add_operation(|mut data| {
        println!("Executing transformation...");
        let new_column: Vec<f64> = data.get("col").map_or(Vec::new(), |v| v.iter().map(|&x| x * 2.0).collect());
        data.insert("result".to_string(), new_column);
        data
    });

    let final_frame = df.compute();

    println!("Computation finished.");
    if let Some(result) = final_frame.get("result") {
        println!("Final column values: {:?}", result);
    }
}

use std::fs::File;
use std::io::{self, Read};
use std::thread::sleep;
use std::time::Duration;

struct ProcessStats {
    pid: u32,
    utime_jiffies: u64,
    stime_jiffies: u64,
    mem_usage_kb: u64,
}

fn read_proc_stat(pid: u32) -> io::Result<String> {
    let path = format!("/proc/{}/stat", pid);
    let mut file = File::open(&path)?;
    let mut contents = String::new();
    file.read_to_string(&mut contents)?; 
    Ok(contents)
}

fn read_meminfo(pid: u32) -> io::Result<u64> {
    let path = format!("/proc/{}/status", pid);
    let mut file = File::open(&path)?;
    let mut contents = String::new();
    file.read_to_string(&mut contents)?; 

    if let Some(line) = contents.lines().find(|line| line.contains("VmSize:")) {
        let parts: Vec<&str> = line.split_whitespace().collect();
        if parts.len() >= 2 { 
            return Ok(parts[1].parse::<u64>().unwrap_or(0));
        }
    }
    Ok(0)
}

fn main() -> io::Result<()> {
    let target_pid: u32 = 1;
    println!("Monitoring PID {}...", target_pid);

    loop {
        match read_proc_stat(target_pid) {
            Ok(stat) => {
                let parts: Vec<&str> = stat.split_whitespace().collect();
                if parts.len() >= 13 { 
                    let utime: u64 = parts[13].parse().unwrap_or(0);
                    let stime: u64 = parts[14].parse().unwrap_or(0);
                    let mem_kb = read_meminfo(target_pid)?;

                    println!("PID: {}, UTime: {}, STime: {}, Mem: {} KB", 
                        target_pid, utime, stime, mem_kb);
                }
            },
            Err(e) => {
                eprintln!("Error reading process stats for PID {}: {}", target_pid, e);
            }
        }
        sleep(Duration::from_secs(2));
    }
}

use std::collections::BTreeMap;

#[derive(Debug, Clone)]
pub struct MemoryBlock {
    pub start_address: u32,
    pub size: usize,
    pub name: String,
}

fn simulate_memory_map() -> BTreeMap<u32, MemoryBlock> {
    let mut map = BTreeMap::new();
    map.insert(0x08000000, MemoryBlock { start_address: 0x08000000, size: 4096, name: "Bootloader".to_string() });
    map.insert(0x08001000, MemoryBlock {
        start_address: 0x08001000,
        size: 8192,
        name: "SensorDataBuffer".to_string(),
    });
    map.insert(0x08002000, MemoryBlock {
        start_address: 0x08002000,
        size: 16384,
        name: "ApplicationLogic".to_string(),
    });
    map
}

fn main() {
    let memory_map = simulate_memory_map();
    println!("--- Simulated Embedded Memory Map ---n");
    for (_, block) in &memory_map {
        println!("Address: 0x{:X} | Size: {} bytes | Name: {}", 
            block.start_address,
            block.size,
            block.name
        );
    }
}
